            /// <summary>
            /// Sobrecarga del método Equals
            /// </summary>
            /// <param name="obj">Objeto a ver sis on iguales</param>
            /// <returns>true si son iguales</returns>
            public override bool Equals(System.Object obj)
            {
                // Si el parametro es null devuelvo false
                if (obj == null)
                {
                    return false;
                }

                // Si el parametro no se puede castear a Nodo, devuelvo false
                Nodo p = obj as Nodo;
                if ((Object)p == null)
                {
                    return false;
                }

                // Devuelve true si los campos coinciden
                return I == p.I && J == p.J;
            }

            /// <summary>
            /// Sobrecarga del método Equals
            /// </summary>
            /// <param name="obj">Objeto a ver sis on iguales</param>
            /// <returns>true si son iguales</returns>
            public bool Equals(Nodo obj)
            {
                // Si el parametro no se puede castear a Nodo, devuelvo false
                Nodo p = obj as Nodo;
                if ((Object)p == null)
                {
                    return false;
                }

                // Devuelve true si los campos coinciden
                return I == p.I && J == p.J;
            }

            /// <summary>
            /// Sobrecarga del operador ==
            /// </summary>
            /// <param name="a">Nodo 1 a comparar</param>
            /// <param name="b">Nodo 2 a comparar</param>
            /// <returns>true si estan en la misma ubicación.</returns>
            public static bool operator ==(Nodo a, Nodo b)
            {
                //si ambos son null o ambos tienen la misma instancia, devuelvo true
                if (Object.ReferenceEquals(a, b))
                {
                    return true;
                }


                // Si uno es null, pero no ambos, devuelvo false.
                if (((object)a == null) || ((object)b == null))
                {
                    return false;
                }

                // Devuelve true si los campos coinciden
                return a.I == b.I && a.J == b.J;
            }

            /// <summary>
            /// Sobrecarga del operador !=
            /// </summary>
            /// <param name="a">Nodo 1 a comparar</param>
            /// <param name="b">Nodo 2 a comparar</param>
            /// <returns>true si son distintos.</returns>
            public static bool operator !=(Nodo a, Nodo b)
            {
                return !(a == b);
            }

            /// <summary>
